const d = $input.first().json;
const fmt = (n) => n ? `$${Number(n).toLocaleString('es-CO')}` : '$0';
const fmtPct = (n) => n !== null && n !== undefined ? `${Number(n) > 0 ? '+' : ''}${Number(n).toFixed(1)}%` : 'N/D';
const desvMTD = Number(d.desviacion_mtd_pct || 0);
const semMTD = desvMTD > 10 ? '🔴' : desvMTD > 5 ? '🟡' : '🟢';
const desvFcast = Number(d.forecast_desviacion_pct || 0);
const semFcast = desvFcast > 10 ? '🔴' : desvFcast > 5 ? '🟡' : '🟢';
const tops = d.top_desviaciones_json || [];
const topTexto = tops.length > 0
  ? tops.map(t => `  • ${t.contratista_nombre || 'Contratista'} — ${t.zona} — ${t.narrativa_corta}`).join('\n')
  : '  • Sin desviaciones críticas activas';
const hoy = new Date();
const fechaStr = hoy.toLocaleDateString('es-CO', { day:'2-digit', month:'short', year:'numeric' });
const mesNombre = hoy.toLocaleDateString('es-CO', { month:'long' });
const altas = d.altas_criticas_abiertas || 0;
const medias = d.medias_abiertas || 0;
const textoResumen = `*Analista OPEX BIA — ${fechaStr}*\nEjecución ayer: *${fmt(d.total_ayer)}*  |  MTD: *${fmt(d.total_mtd)}* (${semMTD} ${fmtPct(d.desviacion_mtd_pct)} vs budget)\n\n🔴 Alertas altas/críticas abiertas: *${altas}*\n🟡 Medias abiertas: *${medias}*\n🟢 Cerradas ayer: *${d.cerradas_ayer || 0}*\n\n*Top desviaciones:*\n${topTexto}\n\nForecast cierre ${mesNombre}: *${fmt(d.proyeccion_central)}* (${semFcast} ${fmtPct(d.forecast_desviacion_pct)} vs budget)`;

return [{
  json: {
    slack_blocks: [
      { type: "section", text: { type: "mrkdwn", text: textoResumen } },
      { type: "divider" },
      { type: "actions", elements: [
        { type: "button", text: { type: "plain_text", text: `Ver cola (${altas})` }, action_id: "ver_cola_aprobacion", style: "primary", value: "ver_cola" },
        { type: "button", text: { type: "plain_text", text: "Abrir dashboard" }, action_id: "abrir_dashboard", value: "dashboard" },
        { type: "button", text: { type: "plain_text", text: "Pausar no críticas" }, action_id: "pausar_alertas", value: "pausar", style: "danger" }
      ]}
    ]
  }
}];
